import React, { useState } from 'react';
import BrandImage from '../../assets/graphics/brand1.png'
import HeaderNavbar from '../navbar/Navbar'
import { faCoffee } from '@fortawesome/free-solid-svg-icons'
import './Header.css'

const Header: React.FunctionComponent = () => {
    const navbarItems = [
        {
            name: "About Me",
            url: "/aboutMe"

        },
        {
            name: "Interest",
            url: "/interest"

        },
        {
            name: "Contact",
            url: "/contact"

        },
    ]
    const navbarIcons = [faCoffee]
    const [collapsed, setCollapsed] = useState(true);
    return (
        <div>
            <HeaderNavbar icons={navbarIcons} toggleNavbar={() => setCollapsed(!collapsed)}collapsed={collapsed} brandImage={BrandImage} color={"fade"} brand={"Hum Boon Chi"} item={navbarItems}></HeaderNavbar>
        </div>
    )

};

export default Header;
